Here's a complete implementation:

### XAML

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             xmlns:models="clr-namespace:MyApp.Models"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemsLayout>
                <LinearItemsLayout Orientation="Vertical"
                                   ItemSizingStrategy="MeasureFirstItem" />
            </CollectionView.ItemsLayout>
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}"
                                   FontSize="12" TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

### ViewModel

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

namespace MyApp.ViewModels;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _itemService;

    public ItemsViewModel(IItemService itemService)
    {
        _itemService = itemService;
    }

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? _currentItem;

    [ObservableProperty]
    private bool _isRefreshing;

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _itemService.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Must set false to hide spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync($"detail?id={CurrentItem.Id}");

        CurrentItem = null; // Reset so the same item can be re-selected
    }
}
```

### Key bindings explained

| XAML property | ViewModel property | Purpose |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool) | Controls the spinner; **set to `false`** when done |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-to-refresh → calls your API |
| `CollectionView.ItemsSource` | `Items` (`ObservableCollection<T>`) | The data source — use `ObservableCollection`, never `List` |
| `CollectionView.SelectedItem` | `CurrentItem` (TwoWay) | Tracks the selected item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on selection → navigates to detail |

### Critical details

- **`RefreshView` wraps `CollectionView`** — pull-to-refresh is not built into CollectionView itself.
- **Set `IsRefreshing = false`** in a `finally` block so the spinner always stops.
- **Reset `CurrentItem = null`** after navigation so the user can re-select the same item.
- **Use `MeasureFirstItem`** sizing strategy for better scroll performance with uniform rows.
- **Use `x:DataType`** on both the page and the `DataTemplate` for compiled bindings.
- **Update collections on the UI thread** via `MainThread.BeginInvokeOnMainThread`.
